What does this program print?

```cpp
#include <iostream>
#include <vector>

enum Fruit { apple, banana, cherry, count };

int main()
{
    std::vector<int> qty(count, 10);
    qty[banana] = 5;
    std::cout << qty[apple] << ' ' << qty[banana] << ' ' << qty[cherry] << '\n';
}
```

This program tries to print the score for every subject, but it has one bug. What is it?

```cpp
#include <iostream>
#include <vector>

enum Subject { english, math, science, count };

int main()
{
    std::vector<int> scores(count);
    scores[english] = 85;
    scores[math]    = 90;
    scores[science] = 78;

    for (int i = 0; i <= count; ++i)
        std::cout << scores[i] << '\n';
}
